 *
 * Unit tests for CURLOPT_H3_STREAM_PRIORITY (RFC 9218 Extensible Priorities)
 ***************************************************************************/
#include "curlcheck.h"

#include <string.h>
#include <stdlib.h>

/*
 * Standalone parser that mirrors the logic in lib/setopt.c for
 * CURLOPT_H3_STREAM_PRIORITY.  Kept here so the unit test has no link
 * dependency on the full libcurl build.
 *
 * Format: "u=N[,i]"
 *   N   – urgency digit 0-7
 *   ,i  – optional incremental flag
 *
 * Returns 0 on success, -1 on parse error.
 */
static int parse_h3_priority(const char *str,
                              int *urgency_out,
                              int *incremental_out)
{
  int urgency = 3;       /* RFC 9218 §4.3 default */
  int incremental = 0;
  const char *p = str;

  if(!str || str[0] == '\0')
    return -1;

  /* Require "u=" prefix */
  if(p[0] != 'u' || p[1] != '=')
    return -1;
  p += 2;

  /* Single urgency digit */
  if(*p < '0' || *p > '7')
    return -1;
  urgency = *p - '0';
  p++;

  /* Optional ",i" incremental flag */
  if(*p == ',') {
    p++;
    if(*p != 'i')
      return -1;
    incremental = 1;
    p++;
  }

  /* Nothing else allowed */
  if(*p != '\0')
    return -1;

  *urgency_out    = urgency;
  *incremental_out = incremental;
  return 0;
}

static CURLcode unit_setup(void)
{
  return CURLE_OK;
}

static void unit_stop(void)
{
}

UNITTEST_START
{
  int urgency    = -1;
  int incremental = -1;
  int rc;

  /* ------------------------------------------------------------------ */
  /* 1. Basic urgency-only: "u=3" */
  urgency = incremental = -1;
  rc = parse_h3_priority("u=3", &urgency, &incremental);
  fail_unless(rc == 0,          "u=3 should parse successfully");
  fail_unless(urgency == 3,     "u=3 urgency should be 3");
  fail_unless(incremental == 0, "u=3 incremental should be 0");

  /* ------------------------------------------------------------------ */
  /* 2. Urgency with incremental flag: "u=5,i" */
  urgency = incremental = -1;
  rc = parse_h3_priority("u=5,i", &urgency, &incremental);
  fail_unless(rc == 0,          "u=5,i should parse successfully");
  fail_unless(urgency == 5,     "u=5,i urgency should be 5");
  fail_unless(incremental == 1, "u=5,i incremental should be 1");

  /* ------------------------------------------------------------------ */
  /* 3. Minimum urgency: "u=0" */
  urgency = incremental = -1;
  rc = parse_h3_priority("u=0", &urgency, &incremental);
  fail_unless(rc == 0,      "u=0 should parse successfully");
  fail_unless(urgency == 0, "u=0 urgency should be 0");

  /* ------------------------------------------------------------------ */
  /* 4. Maximum urgency: "u=7" */
  urgency = incremental = -1;
  rc = parse_h3_priority("u=7", &urgency, &incremental);
  fail_unless(rc == 0,      "u=7 should parse successfully");
  fail_unless(urgency == 7, "u=7 urgency should be 7");

  /* ------------------------------------------------------------------ */
  /* 5. Maximum urgency with incremental: "u=7,i" */
  urgency = incremental = -1;
  rc = parse_h3_priority("u=7,i", &urgency, &incremental);
  fail_unless(rc == 0,          "u=7,i should parse successfully");
  fail_unless(urgency == 7,     "u=7,i urgency should be 7");
  fail_unless(incremental == 1, "u=7,i incremental should be 1");

  /* ------------------------------------------------------------------ */
  /* 6. Invalid: urgency digit out of range "u=8" */
  urgency = incremental = -1;
  rc = parse_h3_priority("u=8", &urgency, &incremental);
  fail_unless(rc != 0, "u=8 should fail (urgency > 7)");

  /* ------------------------------------------------------------------ */
  /* 7. Invalid: missing "u=" prefix */
  rc = parse_h3_priority("3", &urgency, &incremental);
  fail_unless(rc != 0, "bare '3' should fail (missing u= prefix)");

  /* ------------------------------------------------------------------ */
  /* 8. Invalid: empty string */
  rc = parse_h3_priority("", &urgency, &incremental);
  fail_unless(rc != 0, "empty string should fail");

  /* ------------------------------------------------------------------ */
  /* 9. Invalid: NULL pointer */
  rc = parse_h3_priority(NULL, &urgency, &incremental);
  fail_unless(rc != 0, "NULL should fail");

  /* ------------------------------------------------------------------ */
  /* 10. Invalid: trailing garbage after valid input "u=3,ix" */
  rc = parse_h3_priority("u=3,ix", &urgency, &incremental);
  fail_unless(rc != 0, "u=3,ix should fail (trailing garbage)");

  /* ------------------------------------------------------------------ */
  /* 11. Invalid: comma without 'i' flag "u=3,x" */
  rc = parse_h3_priority("u=3,x", &urgency, &incremental);
  fail_unless(rc != 0, "u=3,x should fail (bad incremental token)");

  /* ------------------------------------------------------------------ */
  /* 12. Urgency 1 with incremental: "u=1,i" */
  urgency = incremental = -1;
  rc = parse_h3_priority("u=1,i", &urgency, &incremental);
  fail_unless(rc == 0,          "u=1,i should parse successfully");
  fail_unless(urgency == 1,     "u=1,i urgency should be 1");
  fail_unless(incremental == 1, "u=1,i incremental should be 1");

}
UNITTEST_STOP

